INSERT INTO public.blog_translations (post_id, language, title, content, excerpt, meta_title, meta_description)
SELECT id, lang, title, content, excerpt, mt, md FROM p2,
(VALUES
  ('en', 'Electric Wheelchair Rental in Malaysia — Complete Guide 2026',
   '<h2>Why Rent an Electric Wheelchair?</h2><p>Renting an electric wheelchair in Malaysia is becoming increasingly popular, especially for short-term needs like post-surgery recovery or caring for elderly parents during visits.</p><img src="https://placehold.co/800x400/1B2D5B/FFFFFF?text=Wheelchair+Rental" alt="Electric wheelchair rental Malaysia" /><h2>How Our Rental Works</h2><h3>Step 1: Contact Us</h3><p>WhatsApp us at 6010-888 9849 with your requirements — we''ll recommend the best model for your needs.</p><h3>Step 2: Choose & Pay</h3><p>Select your rental duration and pay via online banking. No credit card required.</p><h3>Step 3: Same-Day Delivery</h3><p>We deliver to your doorstep the same day (for orders before 2pm). Free setup and demonstration included.</p><h2>Rental Pricing</h2><ul><li><strong>Lightweight Model:</strong> RM400/month</li><li><strong>Reclining Model:</strong> RM450/month</li><li><strong>Heavy Duty Model:</strong> RM500/month</li><li><strong>Travel Model:</strong> RM420/month</li></ul><blockquote>All rentals include free delivery, setup, and a demonstration on how to use the wheelchair. No deposit required for monthly rentals.</blockquote><h2>Who Should Rent?</h2><ul><li>Post-surgery patients (hip replacement, knee surgery, stroke recovery)</li><li>Families with elderly parents visiting from overseas</li><li>People who want to try before buying</li><li>Temporary mobility needs (broken leg, sprained ankle)</li></ul><img src="https://placehold.co/800x400/2A4080/FFFFFF?text=Happy+Customer" alt="Happy customer with rental wheelchair" /><h2>FAQ</h2><h3>What is the minimum rental period?</h3><p>Our minimum rental period is 1 month. You can extend month-by-month without penalty.</p><h3>Can I convert my rental to a purchase?</h3><p>Yes! If you decide to buy after renting, we''ll deduct up to 2 months of rental from the purchase price.</p><h3>What if the wheelchair needs repair during rental?</h3><p>We provide free maintenance and replacement during the rental period. Just WhatsApp us and we''ll arrange a swap.</p><h2>Get Started Today</h2><p>WhatsApp us now at 6010-888 9849 to start your rental. Same-day delivery available across Peninsular Malaysia.</p>',
   'Complete guide to renting electric wheelchairs in Malaysia. From RM400/month with free delivery. No deposit, no long-term commitment.',
   'Electric Wheelchair Rental Malaysia 2026',
   'Rent electric wheelchairs in Malaysia from RM400/month. Same-day delivery, free setup, no deposit. WhatsApp 6010-888 9849.'),
  ('ms', 'Sewa Kerusi Roda Elektrik di Malaysia — Panduan Lengkap 2026',
   '<h2>Kenapa Sewa Kerusi Roda Elektrik?</h2><p>Menyewa kerusi roda elektrik di Malaysia semakin popular, terutamanya untuk keperluan jangka pendek seperti pemulihan selepas pembedahan atau menjaga ibu bapa warga emas.</p><img src="https://placehold.co/800x400/1B2D5B/FFFFFF?text=Sewa+Kerusi+Roda" alt="Sewa kerusi roda elektrik Malaysia" /><h2>Cara Sewa Kami Berfungsi</h2><h3>Langkah 1: Hubungi Kami</h3><p>WhatsApp kami di 6010-888 9849 dengan keperluan anda — kami akan syorkan model terbaik.</p><h3>Langkah 2: Pilih & Bayar</h3><p>Pilih tempoh sewaan dan bayar melalui perbankan dalam talian. Tiada kad kredit diperlukan.</p><h3>Langkah 3: Penghantaran Hari Sama</h3><p>Kami hantar ke pintu rumah anda pada hari yang sama (untuk pesanan sebelum 2 petang). Pemasangan dan demonstrasi percuma disertakan.</p><h2>Harga Sewaan</h2><ul><li><strong>Model Ringan:</strong> RM400/bulan</li><li><strong>Model Rebah:</strong> RM450/bulan</li><li><strong>Model Tugas Berat:</strong> RM500/bulan</li><li><strong>Model Travel:</strong> RM420/bulan</li></ul><blockquote>Semua sewaan termasuk penghantaran percuma, pemasangan, dan demonstrasi cara penggunaan. Tiada deposit diperlukan.</blockquote><h2>Siapa Patut Sewa?</h2><ul><li>Pesakit selepas pembedahan</li><li>Keluarga dengan ibu bapa warga emas</li><li>Mereka yang ingin cuba sebelum membeli</li><li>Keperluan mobiliti sementara</li></ul><h2>Soalan Lazim</h2><h3>Apakah tempoh sewaan minimum?</h3><p>Tempoh sewaan minimum kami adalah 1 bulan. Anda boleh melanjutkan bulan demi bulan tanpa penalti.</p><h3>Bolehkah saya tukar sewaan kepada pembelian?</h3><p>Ya! Jika anda memutuskan untuk membeli selepas menyewa, kami akan tolak sehingga 2 bulan sewaan dari harga pembelian.</p><h2>Mula Hari Ini</h2><p>WhatsApp kami sekarang di 6010-888 9849 untuk mulakan sewaan anda.</p>',
   'Panduan lengkap sewa kerusi roda elektrik di Malaysia. Dari RM400/bulan dengan penghantaran percuma. Tiada deposit.',
   'Sewa Kerusi Roda Elektrik Malaysia 2026',
   'Sewa kerusi roda elektrik di Malaysia dari RM400/bulan. Penghantaran hari sama, pemasangan percuma, tiada deposit.'),
  ('zh', '2026年马来西亚电动轮椅租赁完整指南',
   '<h2>为什么租赁电动轮椅？</h2><p>在马来西亚租赁电动轮椅越来越受欢迎，特别适合术后恢复或照顾年迈父母等短期需求。</p><img src="https://placehold.co/800x400/1B2D5B/FFFFFF?text=轮椅租赁" alt="马来西亚电动轮椅租赁" /><h2>租赁流程</h2><h3>第1步：联系我们</h3><p>WhatsApp我们：6010-888 9849，告诉我们您的需求。</p><h3>第2步：选择并付款</h3><p>选择租赁期限，通过网上银行付款。无需信用卡。</p><h3>第3步：当天送货</h3><p>下午2点前下单，当天送到您家门口。免费安装和演示。</p><h2>租赁价格</h2><ul><li><strong>轻便型：</strong>RM400/月</li><li><strong>可躺式：</strong>RM450/月</li><li><strong>重型：</strong>RM500/月</li><li><strong>旅行型：</strong>RM420/月</li></ul><blockquote>所有租赁包含免费送货、安装和使用演示。无需押金。</blockquote><h2>常见问题</h2><h3>最短租期是多少？</h3><p>最短租期为1个月，可按月续租，无罚款。</p><h2>立即开始</h2><p>立即WhatsApp我们：6010-888 9849，开始您的租赁。</p>',
   '马来西亚电动轮椅租赁完整指南。从每月RM400起，免费送货，无押金。',
   '马来西亚电动轮椅租赁指南2026',
   '在马来西亚租赁电动轮椅，每月RM400起。当天送货、免费安装、无押金。WhatsApp 6010-888 9849。')
) AS t(lang, title, content, excerpt, mt, md);

