WITH p3 AS (
  INSERT INTO public.blog_posts (website, slug, status, cover_image_url)
  VALUES ('electric-wheelchair.com.my', 'best-electric-wheelchair-elderly-malaysia-2026', 'published', 'https://placehold.co/800x400/1B2D5B/FFFFFF?text=Best+for+Elderly')
  RETURNING id
