INSERT INTO public.blog_translations (post_id, language, title, content, excerpt, meta_title, meta_description)
SELECT id, lang, title, content, excerpt, mt, md FROM p3,
(VALUES
  ('en', '5 Best Electric Wheelchairs for Elderly in Malaysia (2026)',
   '<h2>Finding the Right Wheelchair for Your Parents</h2><p>Choosing an electric wheelchair for elderly family members requires careful consideration of comfort, safety, and ease of use. Here are our top 5 picks for Malaysian seniors in 2026.</p><img src="https://placehold.co/800x400/1B2D5B/FFFFFF?text=Elderly+Wheelchair" alt="Best electric wheelchair for elderly Malaysia" /><h2>Top 5 Picks</h2><h3>1. Lightweight Foldable — Best Overall</h3><p><strong>Price: RM2,400</strong> | <strong>Rental: RM400/month</strong></p><p>Perfect for daily use. Weighs only 23kg, folds easily for car travel. Simple joystick control ideal for seniors. Battery lasts 15km per charge.</p><h3>2. Reclining Model — Best for Comfort</h3><p><strong>Price: RM2,800</strong> | <strong>Rental: RM450/month</strong></p><p>Full recline with adjustable headrest. Perfect for seniors who spend long hours in the wheelchair. Extra cushioning reduces pressure sores.</p><h3>3. Heavy Duty — Best for Larger Users</h3><p><strong>Price: RM3,200</strong> | <strong>Rental: RM500/month</strong></p><p>Supports up to 120kg with reinforced frame. Wider seat for maximum comfort. Ideal for larger elderly users.</p><h3>4. Travel Compact — Best for Active Seniors</h3><p><strong>Price: RM2,600</strong> | <strong>Rental: RM420/month</strong></p><p>Ultra-compact design fits airplane cabins. Perfect for seniors who still love to travel.</p><h3>5. Indoor Basic — Best Budget Option</h3><p><strong>Price: RM1,800</strong></p><p>Simple, reliable, and affordable. Best for primarily indoor use around the home.</p><img src="https://placehold.co/800x400/2A4080/FFFFFF?text=Wheelchair+Comparison" alt="Comparing electric wheelchairs" /><h2>What to Look for in an Elderly Wheelchair</h2><ul><li><strong>Simple controls:</strong> Large joystick, intuitive direction</li><li><strong>Safety features:</strong> Anti-tip wheels, automatic brakes</li><li><strong>Comfort:</strong> Padded seat, adjustable armrests</li><li><strong>Easy transfer:</strong> Swing-away footrests, flip-up armrests</li></ul><h2>FAQ</h2><h3>Is an electric wheelchair safe for someone with dementia?</h3><p>For mild dementia, yes — with supervision. For moderate to severe dementia, a caregiver-controlled model is recommended. Consult your doctor first.</p><h3>Can elderly use electric wheelchairs indoors?</h3><p>Absolutely. Our lightweight model has a tight turning radius of 75cm, making it perfect for HDB flats and terrace houses in Malaysia.</p><h2>Get Expert Advice</h2><p>Not sure which model is right for your parents? WhatsApp us at 6010-888 9849 and our team will help you choose based on their specific needs.</p>',
   'Top 5 electric wheelchairs for elderly in Malaysia. Compare lightweight, reclining, heavy-duty, and travel models with prices from RM1,800.',
   'Best Electric Wheelchair for Elderly Malaysia',
   'Top 5 electric wheelchairs for elderly in Malaysia 2026. From RM1,800. Compare comfort, safety & features. Free same-day delivery.'),
  ('ms', '5 Kerusi Roda Elektrik Terbaik untuk Warga Emas di Malaysia (2026)',
   '<h2>Mencari Kerusi Roda yang Sesuai untuk Ibu Bapa Anda</h2><p>Memilih kerusi roda elektrik untuk ahli keluarga warga emas memerlukan pertimbangan teliti dari segi keselesaan, keselamatan, dan kemudahan penggunaan.</p><img src="https://placehold.co/800x400/1B2D5B/FFFFFF?text=Kerusi+Roda+Warga+Emas" alt="Kerusi roda elektrik terbaik untuk warga emas" /><h2>5 Pilihan Terbaik</h2><h3>1. Model Ringan Lipat — Terbaik Keseluruhan</h3><p><strong>Harga: RM2,400</strong> | <strong>Sewa: RM400/bulan</strong></p><p>Sesuai untuk kegunaan harian. Berat hanya 23kg, mudah dilipat. Kawalan joystick mudah untuk warga emas.</p><h3>2. Model Rebah — Terbaik untuk Keselesaan</h3><p><strong>Harga: RM2,800</strong> | <strong>Sewa: RM450/bulan</strong></p><p>Rebah penuh dengan sokongan kepala boleh laras. Sesuai untuk warga emas yang lama duduk.</p><h3>3. Model Tugas Berat — Terbaik untuk Pengguna Besar</h3><p><strong>Harga: RM3,200</strong> | <strong>Sewa: RM500/bulan</strong></p><p>Menyokong sehingga 120kg dengan rangka diperkukuh.</p><h3>4. Model Travel — Terbaik untuk Warga Emas Aktif</h3><p><strong>Harga: RM2,600</strong></p><p>Reka bentuk ultra-padat muat kabin kapal terbang.</p><h3>5. Model Asas Dalaman — Pilihan Bajet Terbaik</h3><p><strong>Harga: RM1,800</strong></p><p>Mudah, boleh dipercayai, dan mampu milik.</p><h2>Dapatkan Nasihat Pakar</h2><p>WhatsApp kami di 6010-888 9849 untuk bantuan memilih model yang sesuai.</p>',
   '5 kerusi roda elektrik terbaik untuk warga emas di Malaysia. Bandingkan model ringan, rebah, tugas berat dan travel dari RM1,800.',
   'Kerusi Roda Elektrik Terbaik Warga Emas 2026',
   '5 kerusi roda elektrik terbaik untuk warga emas di Malaysia 2026. Dari RM1,800. Bandingkan keselesaan, keselamatan & ciri.'),
  ('zh', '2026年马来西亚老年人最佳电动轮椅Top 5',
   '<h2>为父母选择合适的轮椅</h2><p>为老年家人选择电动轮椅需要仔细考虑舒适度、安全性和易用性。以下是2026年马来西亚老年人的5款最佳选择。</p><img src="https://placehold.co/800x400/1B2D5B/FFFFFF?text=老年人轮椅" alt="马来西亚老年人最佳电动轮椅" /><h2>前5名推荐</h2><h3>1. 轻便折叠型 — 最佳综合</h3><p><strong>价格：RM2,400</strong> | <strong>租赁：RM400/月</strong></p><p>适合日常使用，仅重23公斤，操作简单。</p><h3>2. 可躺式 — 最舒适</h3><p><strong>价格：RM2,800</strong></p><p>全躺式设计，可调头枕，长时间坐着也舒适。</p><h3>3. 重型 — 适合较大体型</h3><p><strong>价格：RM3,200</strong></p><p>承重120公斤，加固框架。</p><h3>4. 旅行型 — 适合活跃老人</h3><p><strong>价格：RM2,600</strong></p><p>超紧凑设计，可上飞机。</p><h3>5. 室内基础型 — 最佳预算选择</h3><p><strong>价格：RM1,800</strong></p><h2>获取专家建议</h2><p>WhatsApp我们：6010-888 9849，帮您选择最适合的型号。</p>',
   '马来西亚老年人5款最佳电动轮椅。比较轻便、可躺、重型和旅行型号，价格从RM1,800起。',
   '马来西亚老年人最佳电动轮椅2026',
   '2026年马来西亚老年人5款最佳电动轮椅。从RM1,800起，比较舒适度和安全性。免费当天送货。')
) AS t(lang, title, content, excerpt, mt, md);

-- Post 4: Electric vs Manual Wheelchair
WITH p4 AS (
  INSERT INTO public.blog_posts (website, slug, status, cover_image_url)
  VALUES ('electric-wheelchair.com.my', 'electric-wheelchair-vs-manual-wheelchair', 'published', 'https://placehold.co/800x400/2A4080/FFFFFF?text=Electric+vs+Manual')
  RETURNING id
)
INSERT INTO public.blog_translations (post_id, language, title, content, excerpt, meta_title, meta_description)
SELECT id, lang, title, content, excerpt, mt, md FROM p4,
(VALUES
  ('en', 'Electric Wheelchair vs Manual Wheelchair — Which Is Better?',
   '<h2>The Big Question</h2><p>Should you get an electric or manual wheelchair? The answer depends on your specific needs, lifestyle, and budget. Let us break down the key differences.</p><img src="https://placehold.co/800x400/1B2D5B/FFFFFF?text=Electric+vs+Manual" alt="Electric wheelchair vs manual wheelchair comparison" /><h2>Key Differences</h2><h3>Independence</h3><p><strong>Electric:</strong> Full independence — operate with a joystick, no physical strength needed. Perfect for those with limited upper body strength.</p><p><strong>Manual:</strong> Requires arm strength or a caregiver to push. Can be tiring over long distances.</p><h3>Cost</h3><p><strong>Electric:</strong> RM2,400–RM15,000 to buy, or RM400–RM500/month to rent.</p><p><strong>Manual:</strong> RM300–RM2,000. Lower upfront cost but higher physical cost.</p><h3>Portability</h3><p><strong>Electric:</strong> Heavier (23–35kg) but foldable models fit in car boots. Some are airline-approved.</p><p><strong>Manual:</strong> Lighter (8–15kg), easier to transport.</p><h3>Terrain</h3><p><strong>Electric:</strong> Handles slopes, rough surfaces, and long distances easily. Motor does the work.</p><p><strong>Manual:</strong> Struggles on slopes without assistance.</p><img src="https://placehold.co/800x400/F47B20/FFFFFF?text=Comparison+Chart" alt="Wheelchair comparison chart" /><h2>When to Choose Electric</h2><ul><li>Limited upper body strength</li><li>Need to travel long distances independently</li><li>Post-stroke recovery</li><li>Elderly users living alone</li><li>Outdoor use on Malaysian terrain (ramps, slopes)</li></ul><h2>When to Choose Manual</h2><ul><li>Temporary short-term need</li><li>Very tight budget</li><li>Primarily flat indoor use</li><li>Have a full-time caregiver</li></ul><h2>FAQ</h2><h3>Can I get both?</h3><p>Yes! Many families keep a manual wheelchair as backup and use an electric wheelchair for daily mobility. You can also rent the electric one to test it first.</p><h2>Make Your Choice</h2><p>Still unsure? WhatsApp us at 6010-888 9849 and we''ll help you decide based on your situation.</p>',
   'Detailed comparison of electric vs manual wheelchairs. Covers independence, cost, portability, and terrain handling to help you decide.',
   'Electric vs Manual Wheelchair Comparison',
   'Electric wheelchair vs manual wheelchair — which is better? Compare independence, cost, portability. From RM400/month rental. WhatsApp us.'),
  ('ms', 'Kerusi Roda Elektrik vs Manual — Mana Lebih Baik?',
   '<h2>Persoalan Besar</h2><p>Patut anda dapatkan kerusi roda elektrik atau manual? Jawapannya bergantung kepada keperluan, gaya hidup, dan bajet anda.</p><img src="https://placehold.co/800x400/1B2D5B/FFFFFF?text=Elektrik+vs+Manual" alt="Perbandingan kerusi roda elektrik vs manual" /><h2>Perbezaan Utama</h2><h3>Kebebasan</h3><p><strong>Elektrik:</strong> Kebebasan penuh — kendalikan dengan joystick, tiada kekuatan fizikal diperlukan.</p><p><strong>Manual:</strong> Memerlukan kekuatan tangan atau penjaga untuk menolak.</p><h3>Kos</h3><p><strong>Elektrik:</strong> RM2,400–RM15,000 untuk beli, atau RM400–RM500/bulan untuk sewa.</p><p><strong>Manual:</strong> RM300–RM2,000. Kos awal lebih rendah.</p><h3>Mudah Alih</h3><p><strong>Elektrik:</strong> Lebih berat (23–35kg) tetapi model lipat muat dalam but kereta.</p><p><strong>Manual:</strong> Lebih ringan (8–15kg), lebih mudah diangkut.</p><h2>Bila Pilih Elektrik</h2><ul><li>Kekuatan badan atas terhad</li><li>Perlu bergerak jarak jauh secara bebas</li><li>Pemulihan strok</li><li>Warga emas yang tinggal sendiri</li></ul><h2>Buat Pilihan Anda</h2><p>Masih tidak pasti? WhatsApp kami di 6010-888 9849.</p>',
   'Perbandingan terperinci kerusi roda elektrik vs manual. Merangkumi kebebasan, kos, mudah alih untuk membantu anda membuat keputusan.',
   'Kerusi Roda Elektrik vs Manual — Mana Lebih?',
   'Perbandingan kerusi roda elektrik vs manual. Bandingkan kebebasan, kos, mudah alih. Sewa dari RM400/bulan. WhatsApp kami.'),
  ('zh', '电动轮椅 vs 手动轮椅 — 哪个更好？',
   '<h2>重大问题</h2><p>应该选择电动还是手动轮椅？答案取决于您的具体需求、生活方式和预算。</p><img src="https://placehold.co/800x400/1B2D5B/FFFFFF?text=电动vs手动" alt="电动轮椅vs手动轮椅比较" /><h2>主要区别</h2><h3>独立性</h3><p><strong>电动：</strong>完全独立——用操纵杆操作，无需体力。</p><p><strong>手动：</strong>需要臂力或护理人员推动。</p><h3>费用</h3><p><strong>电动：</strong>RM2,400–RM15,000购买，或RM400–RM500/月租赁。</p><p><strong>手动：</strong>RM300–RM2,000。</p><h2>何时选择电动</h2><ul><li>上身力量有限</li><li>需要长距离独立出行</li><li>中风恢复期</li><li>独居老人</li></ul><h2>做出选择</h2><p>仍然不确定？WhatsApp我们：6010-888 9849。</p>',
   '电动轮椅和手动轮椅的详细比较。涵盖独立性、费用、便携性。',
   '电动轮椅vs手动轮椅比较',
   '电动轮椅vs手动轮椅——哪个更好？比较独立性、费用、便携性。租赁从RM400/月起。')
) AS t(lang, title, content, excerpt, mt, md);

-- Post 5: Battery Care Guide
WITH p5 AS (
  INSERT INTO public.blog_posts (website, slug, status, cover_image_url)
  VALUES ('electric-wheelchair.com.my', 'cara-jaga-bateri-kerusi-roda-elektrik', 'published', 'https://placehold.co/800x400/1B2D5B/FFFFFF?text=Jaga+Bateri')
  RETURNING id
)
INSERT INTO public.blog_translations (post_id, language, title, content, excerpt, meta_title, meta_description)
SELECT id, lang, title, content, excerpt, mt, md FROM p5,
(VALUES
  ('en', 'How to Care for Your Electric Wheelchair Battery — Make It Last',
   '<h2>Why Battery Care Matters</h2><p>The battery is the heart of your electric wheelchair. Proper care can extend its life from 2 years to 5 years, saving you RM500–RM1,500 on replacements.</p><img src="https://placehold.co/800x400/1B2D5B/FFFFFF?text=Battery+Care" alt="Electric wheelchair battery care tips" /><h2>7 Essential Battery Care Tips</h2><h3>1. Charge After Every Use</h3><p>Don''t wait until the battery is completely flat. Charge after each outing, even if you only used 20% of the battery. Lithium-ion batteries prefer partial charges over deep discharges.</p><h3>2. Don''t Overcharge</h3><p>Unplug once fully charged (6-8 hours). Most modern chargers auto-stop, but it''s good practice to unplug. Overcharging can degrade battery cells over time.</p><h3>3. Store in Cool, Dry Place</h3><p>Malaysia''s heat can damage batteries. Store your wheelchair indoors, away from direct sunlight. Ideal temperature is 20-25°C. Never leave it in a hot car boot for extended periods.</p><h3>4. Charge at Least Once a Month (Even If Not Using)</h3><p>If the wheelchair is stored for a long period, charge the battery at least once a month to prevent deep discharge damage.</p><h3>5. Use the Original Charger</h3><p>Always use the charger that came with your wheelchair. Third-party chargers may have incorrect voltage and damage the battery.</p><h3>6. Check Tyre Pressure</h3><p>Under-inflated tyres make the motor work harder, draining the battery faster. Check tyre pressure monthly.</p><h3>7. Avoid Extreme Loads</h3><p>Don''t exceed the wheelchair''s weight capacity. Overloading strains the motor and battery, reducing lifespan.</p><img src="https://placehold.co/800x400/2A4080/FFFFFF?text=Battery+Lifespan" alt="Electric wheelchair battery lifespan chart" /><h2>Signs Your Battery Needs Replacing</h2><ul><li>Range drops below 50% of original</li><li>Takes much longer to charge</li><li>Wheelchair moves slower than usual</li><li>Battery indicator drops rapidly</li></ul><h2>Battery Replacement</h2><p>We stock genuine replacement batteries for all our models. Prices range from RM500–RM1,500 depending on capacity. Installation is free — just WhatsApp us.</p><h2>FAQ</h2><h3>How long does an electric wheelchair battery last?</h3><p>With proper care, 3-5 years. Without care, as little as 1-2 years.</p><h2>Need a New Battery?</h2><p>WhatsApp us at 6010-888 9849 for battery replacement or any wheelchair maintenance needs.</p>',
   'Essential tips to extend your electric wheelchair battery life. Learn proper charging, storage, and maintenance for Malaysian climate.',
   'Electric Wheelchair Battery Care Tips',
   'How to care for electric wheelchair batteries. 7 tips to extend battery life to 5 years. Replacement from RM500. WhatsApp us.'),
  ('ms', 'Cara Jaga Bateri Kerusi Roda Elektrik Supaya Tahan Lama',
   '<h2>Kenapa Penjagaan Bateri Penting</h2><p>Bateri adalah jantung kerusi roda elektrik anda. Penjagaan yang betul boleh memanjangkan hayatnya dari 2 tahun kepada 5 tahun, menjimatkan RM500–RM1,500 untuk penggantian.</p><img src="https://placehold.co/800x400/1B2D5B/FFFFFF?text=Jaga+Bateri" alt="Tip penjagaan bateri kerusi roda elektrik" /><h2>7 Tip Penjagaan Bateri</h2><h3>1. Cas Selepas Setiap Penggunaan</h3><p>Jangan tunggu sehingga bateri habis sepenuhnya. Cas selepas setiap keluar, walaupun hanya guna 20% bateri.</p><h3>2. Jangan Overcharge</h3><p>Cabut setelah penuh (6-8 jam). Kebanyakan pengecas moden berhenti automatik, tetapi amalan baik untuk mencabut.</p><h3>3. Simpan di Tempat Sejuk dan Kering</h3><p>Cuaca panas Malaysia boleh merosakkan bateri. Simpan kerusi roda di dalam rumah, jauh dari cahaya matahari langsung.</p><h3>4. Cas Sekurang-kurangnya Sekali Sebulan</h3><p>Jika kerusi roda disimpan lama, cas bateri sekurang-kurangnya sekali sebulan.</p><h3>5. Guna Pengecas Asal</h3><p>Sentiasa guna pengecas yang datang dengan kerusi roda anda.</p><h3>6. Periksa Tekanan Tayar</h3><p>Tayar kurang angin buat motor kerja lebih keras, menghabiskan bateri lebih cepat.</p><h3>7. Elakkan Beban Berlebihan</h3><p>Jangan melebihi kapasiti berat kerusi roda.</p><h2>Tanda Bateri Perlu Ditukar</h2><ul><li>Jarak jatuh bawah 50% asal</li><li>Ambil masa lebih lama untuk cas</li><li>Kerusi roda bergerak lebih perlahan</li></ul><h2>Perlukan Bateri Baru?</h2><p>WhatsApp kami di 6010-888 9849 untuk penggantian bateri.</p>',
   'Tip penting untuk memanjangkan hayat bateri kerusi roda elektrik. Belajar cara cas, simpan dan penyelenggaraan yang betul.',
   'Cara Jaga Bateri Kerusi Roda Elektrik',
   'Cara jaga bateri kerusi roda elektrik supaya tahan lama. 7 tip untuk hayat bateri sehingga 5 tahun. Penggantian dari RM500.'),
  ('zh', '如何保养电动轮椅电池——延长使用寿命',
   '<h2>为什么电池保养很重要</h2><p>电池是电动轮椅的核心。正确保养可将寿命从2年延长到5年，节省RM500–RM1,500的更换费用。</p><img src="https://placehold.co/800x400/1B2D5B/FFFFFF?text=电池保养" alt="电动轮椅电池保养技巧" /><h2>7个重要保养技巧</h2><h3>1. 每次使用后充电</h3><p>不要等电池完全耗尽。每次外出后充电。</p><h3>2. 不要过度充电</h3><p>充满后拔掉（6-8小时）。</p><h3>3. 存放在阴凉干燥处</h3><p>马来西亚的高温会损坏电池。将轮椅存放在室内。</p><h3>4. 至少每月充电一次</h3><p>即使不使用，也要每月充电一次。</p><h2>需要新电池？</h2><p>WhatsApp我们：6010-888 9849。</p>',
   '延长电动轮椅电池寿命的重要技巧。学习正确的充电、存放和维护方法。',
   '电动轮椅电池保养技巧',
   '如何保养电动轮椅电池。7个技巧延长电池寿命至5年。更换从RM500起。立即WhatsApp咨询。')
) AS t(lang, title, content, excerpt, mt, md);

-- Post 6-10 (shorter entries to keep file manageable)

-- Post 6: Electric Wheelchair Price Malaysia
WITH p6 AS (
  INSERT INTO public.blog_posts (website, slug, status, cover_image_url)
  VALUES ('electric-wheelchair.com.my', 'electric-wheelchair-price-malaysia-2026', 'published', 'https://placehold.co/800x400/F47B20/FFFFFF?text=Price+Guide')
  RETURNING id
)
INSERT INTO public.blog_translations (post_id, language, title, content, excerpt, meta_title, meta_description)
SELECT id, lang, title, content, excerpt, mt, md FROM p6,
(VALUES
  ('en', 'How Much Does an Electric Wheelchair Cost in Malaysia? (2026 Prices)',
   '<h2>Electric Wheelchair Prices in Malaysia</h2><p>Electric wheelchair prices in Malaysia range from RM1,800 to RM15,000. The price depends on features, brand, weight capacity, and battery life.</p><img src="https://placehold.co/800x400/1B2D5B/FFFFFF?text=Price+Guide+2026" alt="Electric wheelchair prices Malaysia 2026" /><h2>Price Breakdown by Category</h2><h3>Budget Range: RM1,800 – RM2,500</h3><p>Basic electric wheelchairs suitable for indoor use. Limited battery range (8-10km), basic seat cushion, simple joystick control.</p><h3>Mid-Range: RM2,400 – RM5,000</h3><p>Our most popular range. Foldable designs, 15-20km battery range, KKM certified, comfortable seats. This is where most buyers find the best value.</p><h3>Premium: RM5,000 – RM15,000</h3><p>Advanced features like full recline, suspension, 25-30km range, premium materials, and smart features like Bluetooth connectivity.</p><h2>Rental Alternative</h2><p>Can''t afford to buy? Our rental plans start from RM400/month with option to convert to purchase later.</p><img src="https://placehold.co/800x400/2A4080/FFFFFF?text=Rental+Plans" alt="Electric wheelchair rental plans" /><h2>Ways to Save</h2><ul><li><strong>EPF/KWSP Withdrawal:</strong> May be eligible under medical equipment category</li><li><strong>JKM Subsidy:</strong> OKU card holders may qualify for government subsidies</li><li><strong>Rental-to-Own:</strong> Rent first, deduct up to 2 months from purchase price</li><li><strong>Installment Plans:</strong> RM400/month for 12 months</li></ul><h2>FAQ</h2><h3>Why are some electric wheelchairs so expensive?</h3><p>Premium wheelchairs use aircraft-grade aluminium, lithium-ion batteries, and advanced motors. They also come with better warranties and after-sales support.</p><h2>Get a Quote</h2><p>WhatsApp us at 6010-888 9849 for personalized pricing based on your needs.</p>',
   'Complete electric wheelchair price guide for Malaysia 2026. From RM1,800 to RM15,000. Compare budget, mid-range, and premium options.',
   'Electric Wheelchair Price Malaysia 2026',
   'Electric wheelchair prices in Malaysia from RM1,800-RM15,000. Budget to premium options. Rental from RM400/month. Get a free quote now.'),
  ('ms', 'Berapa Harga Kerusi Roda Elektrik di Malaysia? (Harga 2026)',
   '<h2>Harga Kerusi Roda Elektrik di Malaysia</h2><p>Harga kerusi roda elektrik di Malaysia bermula dari RM1,800 hingga RM15,000 bergantung kepada ciri, jenama, dan kapasiti.</p><img src="https://placehold.co/800x400/1B2D5B/FFFFFF?text=Panduan+Harga" alt="Harga kerusi roda elektrik Malaysia 2026" /><h2>Pecahan Harga</h2><h3>Bajet: RM1,800 – RM2,500</h3><p>Kerusi roda elektrik asas untuk kegunaan dalaman.</p><h3>Pertengahan: RM2,400 – RM5,000</h3><p>Julat paling popular kami. Reka bentuk lipat, jarak bateri 15-20km, sijil KKM.</p><h3>Premium: RM5,000 – RM15,000</h3><p>Ciri canggih seperti rebah penuh, suspensi, dan jarak 25-30km.</p><h2>Pilihan Sewa</h2><p>Tidak mampu beli? Pelan sewaan kami bermula dari RM400/bulan.</p><h2>Cara Jimat</h2><ul><li><strong>Pengeluaran EPF/KWSP</strong></li><li><strong>Subsidi JKM</strong> untuk pemegang kad OKU</li><li><strong>Sewa-ke-Milik</strong></li></ul><h2>Dapatkan Sebut Harga</h2><p>WhatsApp kami di 6010-888 9849.</p>',
   'Panduan harga kerusi roda elektrik Malaysia 2026. Dari RM1,800 hingga RM15,000. Bandingkan pilihan bajet hingga premium.',
   'Harga Kerusi Roda Elektrik Malaysia 2026',
   'Harga kerusi roda elektrik di Malaysia dari RM1,800-RM15,000. Pilihan bajet hingga premium. Sewa dari RM400/bulan.'),
  ('zh', '马来西亚电动轮椅多少钱？（2026年价格）',
   '<h2>马来西亚电动轮椅价格</h2><p>马来西亚电动轮椅价格从RM1,800到RM15,000不等。</p><img src="https://placehold.co/800x400/1B2D5B/FFFFFF?text=价格指南" alt="马来西亚电动轮椅价格2026" /><h2>价格分类</h2><h3>经济型：RM1,800 – RM2,500</h3><p>适合室内使用的基础电动轮椅。</p><h3>中档：RM2,400 – RM5,000</h3><p>最受欢迎。可折叠，15-20公里续航，KKM认证。</p><h3>高端：RM5,000 – RM15,000</h3><p>高级功能，25-30公里续航。</p><h2>获取报价</h2><p>WhatsApp我们：6010-888 9849。</p>',
   '2026年马来西亚电动轮椅完整价格指南。从RM1,800到RM15,000。',
   '马来西亚电动轮椅价格2026',
   '马来西亚电动轮椅价格从RM1,800-RM15,000。经济到高端选择。租赁从RM400/月起。')
) AS t(lang, title, content, excerpt, mt, md);

-- Post 7: KKM Certification
WITH p7 AS (
  INSERT INTO public.blog_posts (website, slug, status, cover_image_url)
  VALUES ('electric-wheelchair.com.my', 'kkm-certified-electric-wheelchair-malaysia', 'published', 'https://placehold.co/800x400/1B2D5B/FFFFFF?text=KKM+Certified')
  RETURNING id
)
INSERT INTO public.blog_translations (post_id, language, title, content, excerpt, meta_title, meta_description)
SELECT id, lang, title, content, excerpt, mt, md FROM p7,
(VALUES
  ('en', 'KKM Certified Electric Wheelchairs — Why It Matters',
   '<h2>What is KKM Certification?</h2><p>KKM stands for Kementerian Kesihatan Malaysia (Ministry of Health Malaysia). KKM certification means an electric wheelchair has passed rigorous safety and quality tests required by the Malaysian government.</p><img src="https://placehold.co/800x400/1B2D5B/FFFFFF?text=KKM+Certified" alt="KKM certified electric wheelchair Malaysia" /><h2>Why KKM Certification Matters</h2><h3>Safety Assurance</h3><p>KKM-certified wheelchairs have been tested for electrical safety, structural integrity, and fire resistance. This protects you from cheap imports that may be unsafe.</p><h3>Insurance & Claims</h3><p>Many insurance companies and EPF only cover KKM-certified medical devices. Without certification, your claim may be rejected.</p><h3>Warranty Protection</h3><p>KKM-certified products typically come with proper warranties backed by authorized distributors in Malaysia.</p><img src="https://placehold.co/800x400/2A4080/FFFFFF?text=Safety+Standards" alt="Wheelchair safety standards" /><h2>How to Check KKM Certification</h2><ul><li>Ask for the MDA (Medical Device Authority) registration number</li><li>Check the MDA database at mdb.gov.my</li><li>Look for the KKM certification sticker on the wheelchair</li><li>Request the certificate from the seller</li></ul><h2>Risks of Non-Certified Wheelchairs</h2><ul><li>Battery may overheat or explode</li><li>Motor may fail unexpectedly</li><li>No warranty or after-sales support</li><li>Cannot claim from insurance or EPF</li></ul><h2>All Our Wheelchairs Are KKM Certified</h2><p>Every electric wheelchair we sell or rent carries KKM certification. We can provide the MDA registration number upon request.</p><h2>Questions?</h2><p>WhatsApp us at 6010-888 9849 to verify certification for any model.</p>',
   'Learn why KKM certification matters for electric wheelchairs in Malaysia. Safety, insurance claims, and how to verify certification.',
   'KKM Certified Electric Wheelchair Malaysia',
   'Why KKM certification matters for electric wheelchairs in Malaysia. Safety tested, insurance eligible. All our wheelchairs are certified.'),
  ('ms', 'Kerusi Roda Elektrik Bertauliah KKM — Mengapa Ia Penting',
   '<h2>Apa itu Sijil KKM?</h2><p>KKM bermaksud Kementerian Kesihatan Malaysia. Sijil KKM bermakna kerusi roda elektrik telah lulus ujian keselamatan dan kualiti yang ketat.</p><img src="https://placehold.co/800x400/1B2D5B/FFFFFF?text=Sijil+KKM" alt="Kerusi roda elektrik bertauliah KKM" /><h2>Kenapa Sijil KKM Penting</h2><h3>Jaminan Keselamatan</h3><p>Kerusi roda bertauliah KKM telah diuji untuk keselamatan elektrik, integriti struktur, dan ketahanan api.</p><h3>Insurans & Tuntutan</h3><p>Banyak syarikat insurans dan EPF hanya meliputi peranti perubatan bertauliah KKM.</p><h2>Semua Kerusi Roda Kami Bertauliah KKM</h2><p>Setiap kerusi roda elektrik yang kami jual atau sewakan mempunyai sijil KKM.</p><p>WhatsApp kami di 6010-888 9849 untuk pengesahan.</p>',
   'Ketahui mengapa sijil KKM penting untuk kerusi roda elektrik di Malaysia. Keselamatan, tuntutan insurans, dan cara mengesahkan.',
   'Kerusi Roda Elektrik Bertauliah KKM',
   'Mengapa sijil KKM penting untuk kerusi roda elektrik. Diuji keselamatan, layak insurans. Semua kerusi roda kami bertauliah.'),
  ('zh', 'KKM认证电动轮椅——为什么很重要',
   '<h2>什么是KKM认证？</h2><p>KKM是马来西亚卫生部。KKM认证意味着电动轮椅已通过严格的安全和质量测试。</p><img src="https://placehold.co/800x400/1B2D5B/FFFFFF?text=KKM认证" alt="KKM认证电动轮椅" /><h2>为什么KKM认证重要</h2><h3>安全保障</h3><p>经过电气安全、结构完整性和防火测试。</p><h3>保险理赔</h3><p>许多保险公司和EPF只覆盖KKM认证的医疗设备。</p><h2>我们所有轮椅都有KKM认证</h2><p>WhatsApp我们：6010-888 9849验证认证。</p>',
   '了解KKM认证对马来西亚电动轮椅的重要性。安全、保险理赔和认证验证方法。',
   'KKM认证电动轮椅马来西亚',
   '为什么KKM认证对电动轮椅很重要。安全测试、保险资格。我们所有轮椅均获认证。')
) AS t(lang, title, content, excerpt, mt, md);

-- Post 8: Stroke Patient Wheelchair Guide
WITH p8 AS (
  INSERT INTO public.blog_posts (website, slug, status, cover_image_url)
  VALUES ('electric-wheelchair.com.my', 'kerusi-roda-elektrik-pesakit-strok', 'published', 'https://placehold.co/800x400/1B2D5B/FFFFFF?text=Pesakit+Strok')
  RETURNING id
)
INSERT INTO public.blog_translations (post_id, language, title, content, excerpt, meta_title, meta_description)
SELECT id, lang, title, content, excerpt, mt, md FROM p8,
(VALUES
  ('en', 'Electric Wheelchair for Stroke Patients — What You Need to Know',
   '<h2>Regaining Mobility After Stroke</h2><p>A stroke can dramatically affect mobility. An electric wheelchair provides independence during recovery, allowing stroke patients to move freely without relying entirely on caregivers.</p><img src="https://placehold.co/800x400/1B2D5B/FFFFFF?text=Stroke+Recovery" alt="Electric wheelchair for stroke patients" /><h2>Why Electric Over Manual for Stroke?</h2><p>After a stroke, one side of the body is often weakened (hemiplegia). A manual wheelchair requires both arms to propel, which is impossible for many stroke survivors. An electric wheelchair only needs one hand on the joystick.</p><h2>Best Features for Stroke Patients</h2><ul><li><strong>One-hand joystick control</strong> — can be mounted on either side</li><li><strong>Reclining backrest</strong> — reduces fatigue during long sessions</li><li><strong>Anti-tip wheels</strong> — prevents backward tipping</li><li><strong>Adjustable footrests</strong> — accommodates swollen legs</li><li><strong>Easy transfer</strong> — swing-away armrests for bed-to-chair moves</li></ul><img src="https://placehold.co/800x400/2A4080/FFFFFF?text=Wheelchair+Features" alt="Wheelchair features for stroke recovery" /><h2>Rental for Recovery Period</h2><p>Most stroke patients need a wheelchair for 3-12 months during rehabilitation. Our rental from RM400/month is ideal — no need to buy if recovery is progressing well.</p><blockquote>Tip: Many physiotherapists recommend transitioning from wheelchair to walker as recovery progresses. Renting allows you to return the wheelchair when no longer needed.</blockquote><h2>FAQ</h2><h3>Can a stroke patient operate an electric wheelchair safely?</h3><p>Yes, if they have control of one hand and adequate cognitive function. Always consult your neurologist or physiotherapist first. We can arrange a trial session.</p><h2>Get Expert Advice</h2><p>WhatsApp us at 6010-888 9849 — we''ll recommend the best wheelchair for your recovery stage.</p>',
   'Guide to electric wheelchairs for stroke patients. One-hand joystick control, reclining support, and rental options for recovery periods.',
   'Electric Wheelchair for Stroke Patients',
   'Electric wheelchair guide for stroke patients in Malaysia. One-hand control, reclining support. Rent from RM400/month during recovery.'),
  ('ms', 'Kerusi Roda Elektrik untuk Pesakit Strok — Apa Yang Perlu Anda Tahu',
   '<h2>Mendapatkan Semula Mobiliti Selepas Strok</h2><p>Strok boleh menjejaskan mobiliti secara dramatik. Kerusi roda elektrik memberikan kebebasan semasa pemulihan, membolehkan pesakit strok bergerak tanpa bergantung sepenuhnya kepada penjaga.</p><img src="https://placehold.co/800x400/1B2D5B/FFFFFF?text=Pemulihan+Strok" alt="Kerusi roda elektrik untuk pesakit strok" /><h2>Kenapa Elektrik Lebih Baik untuk Pesakit Strok?</h2><p>Selepas strok, satu bahagian badan sering lemah (hemiplegia). Kerusi roda manual memerlukan kedua-dua tangan. Kerusi roda elektrik hanya perlukan satu tangan pada joystick.</p><h2>Ciri Terbaik untuk Pesakit Strok</h2><ul><li><strong>Kawalan joystick satu tangan</strong></li><li><strong>Sandaran rebah</strong></li><li><strong>Roda anti-terbalik</strong></li><li><strong>Penyangga kaki boleh laras</strong></li></ul><h2>Sewa untuk Tempoh Pemulihan</h2><p>Kebanyakan pesakit strok memerlukan kerusi roda selama 3-12 bulan. Sewaan kami dari RM400/bulan adalah ideal.</p><h2>Dapatkan Nasihat Pakar</h2><p>WhatsApp kami di 6010-888 9849.</p>',
   'Panduan kerusi roda elektrik untuk pesakit strok. Kawalan joystick satu tangan, sokongan rebah, dan pilihan sewa untuk pemulihan.',
   'Kerusi Roda Elektrik untuk Pesakit Strok',
   'Panduan kerusi roda elektrik untuk pesakit strok di Malaysia. Kawalan satu tangan, rebah. Sewa dari RM400/bulan.'),
  ('zh', '中风患者电动轮椅——您需要知道的一切',
   '<h2>中风后恢复行动能力</h2><p>中风会严重影响行动能力。电动轮椅在恢复期间提供独立性。</p><img src="https://placehold.co/800x400/1B2D5B/FFFFFF?text=中风恢复" alt="中风患者电动轮椅" /><h2>为什么中风患者选择电动？</h2><p>中风后身体一侧往往虚弱。手动轮椅需要双手推动，电动轮椅只需一只手操作操纵杆。</p><h2>最佳功能</h2><ul><li>单手操纵杆控制</li><li>可躺式靠背</li><li>防倾翻轮</li></ul><h2>获取专家建议</h2><p>WhatsApp我们：6010-888 9849。</p>',
   '中风患者电动轮椅指南。单手操纵杆控制、可躺式支撑、恢复期租赁选项。',
   '中风患者电动轮椅指南',
   '马来西亚中风患者电动轮椅指南。单手控制，可躺式。恢复期租赁从RM400/月起。')
) AS t(lang, title, content, excerpt, mt, md);

-- Post 9: Wheelchair on Plane
WITH p9 AS (
  INSERT INTO public.blog_posts (website, slug, status, cover_image_url)
  VALUES ('electric-wheelchair.com.my', 'electric-wheelchair-on-plane-malaysia', 'published', 'https://placehold.co/800x400/2A4080/FFFFFF?text=Wheelchair+on+Plane')
  RETURNING id
)
INSERT INTO public.blog_translations (post_id, language, title, content, excerpt, meta_title, meta_description)
SELECT id, lang, title, content, excerpt, mt, md FROM p9,
(VALUES
  ('en', 'Can You Bring an Electric Wheelchair on a Plane? (Malaysia Guide)',
   '<h2>Flying with an Electric Wheelchair</h2><p>Yes, you can bring an electric wheelchair on a plane! But there are rules and procedures you need to follow. Here''s everything you need to know for flying from Malaysian airports.</p><img src="https://placehold.co/800x400/1B2D5B/FFFFFF?text=Wheelchair+Air+Travel" alt="Electric wheelchair on airplane Malaysia" /><h2>Airline Rules</h2><h3>Malaysia Airlines</h3><p>Accepts electric wheelchairs as checked baggage at no extra charge. Battery must be disconnected and terminals insulated. Lithium-ion batteries under 300Wh are accepted. Notify at least 48 hours before departure.</p><h3>AirAsia</h3><p>Accepts electric wheelchairs. Must book Special Assistance online or call their hotline. Battery rules same as above. Limited to 1 wheelchair per passenger.</p><h3>General Rules for All Airlines</h3><ul><li>Notify the airline 48 hours before departure</li><li>Arrive at airport 3 hours early</li><li>Battery must be removable (lithium-ion preferred)</li><li>Battery capacity must be under 300Wh</li><li>Terminals must be insulated with tape</li><li>Wheelchair gate-checked (last on, first off)</li></ul><img src="https://placehold.co/800x400/F47B20/FFFFFF?text=Airport+Tips" alt="Airport tips for wheelchair users" /><h2>Our Travel-Friendly Models</h2><p>Our Travel Electric Wheelchair (RM2,600) is specifically designed for air travel — airline-approved lithium battery, compact fold, and under 25kg total weight.</p><h2>FAQ</h2><h3>Will my wheelchair be damaged during the flight?</h3><p>Airlines are required to handle wheelchairs with care. Consider getting wheelchair travel insurance for extra protection.</p><h2>Plan Your Trip</h2><p>WhatsApp us at 6010-888 9849 for advice on the best travel wheelchair model.</p>',
   'Complete guide to flying with an electric wheelchair from Malaysia. Rules for Malaysia Airlines, AirAsia, and tips for smooth airport experience.',
   'Electric Wheelchair on Plane Malaysia Guide',
   'Can you bring electric wheelchair on a plane? Malaysia Airlines & AirAsia rules. Travel wheelchair from RM2,600. WhatsApp for advice.'),
  ('ms', 'Bolehkah Bawa Kerusi Roda Elektrik Naik Kapal Terbang? (Panduan Malaysia)',
   '<h2>Terbang dengan Kerusi Roda Elektrik</h2><p>Ya, anda boleh bawa kerusi roda elektrik naik kapal terbang! Tetapi ada peraturan yang perlu dipatuhi.</p><img src="https://placehold.co/800x400/1B2D5B/FFFFFF?text=Kerusi+Roda+Kapal+Terbang" alt="Kerusi roda elektrik di kapal terbang" /><h2>Peraturan Syarikat Penerbangan</h2><h3>Malaysia Airlines</h3><p>Menerima kerusi roda elektrik sebagai bagasi tanpa caj tambahan. Bateri mesti diputuskan sambungan. Maklumkan 48 jam sebelum berlepas.</p><h3>AirAsia</h3><p>Menerima kerusi roda elektrik. Mesti tempah Bantuan Khas dalam talian.</p><h2>Model Travel Kami</h2><p>Model Travel (RM2,600) direka khas untuk perjalanan udara — bateri lithium diluluskan syarikat penerbangan.</p><h2>Rancang Perjalanan Anda</h2><p>WhatsApp kami di 6010-888 9849.</p>',
   'Panduan lengkap terbang dengan kerusi roda elektrik dari Malaysia. Peraturan Malaysia Airlines, AirAsia, dan tip.',
   'Kerusi Roda Elektrik Naik Kapal Terbang',
   'Bolehkah bawa kerusi roda elektrik naik kapal terbang? Peraturan Malaysia Airlines & AirAsia. Model travel dari RM2,600.'),
  ('zh', '电动轮椅可以上飞机吗？（马来西亚指南）',
   '<h2>带电动轮椅坐飞机</h2><p>可以！但有规则需要遵守。</p><img src="https://placehold.co/800x400/1B2D5B/FFFFFF?text=轮椅坐飞机" alt="电动轮椅上飞机" /><h2>航空公司规定</h2><h3>马来西亚航空</h3><p>接受电动轮椅作为托运行李，无额外费用。电池必须断开。出发前48小时通知。</p><h3>亚航</h3><p>接受电动轮椅。需在线预订特殊协助。</p><h2>我们的旅行型号</h2><p>旅行电动轮椅（RM2,600）专为航空旅行设计。</p><h2>WhatsApp我们：6010-888 9849。</h2>',
   '马来西亚带电动轮椅坐飞机完整指南。马航、亚航规定和机场提示。',
   '电动轮椅可以上飞机吗？马来西亚指南',
   '电动轮椅可以带上飞机吗？马航和亚航规定。旅行轮椅从RM2,600起。立即WhatsApp咨询。')
) AS t(lang, title, content, excerpt, mt, md);

-- Post 10: Sewa vs Beli
WITH p10 AS (
  INSERT INTO public.blog_posts (website, slug, status, cover_image_url)
  VALUES ('electric-wheelchair.com.my', 'sewa-vs-beli-kerusi-roda-elektrik-malaysia', 'published', 'https://placehold.co/800x400/F47B20/FFFFFF?text=Sewa+vs+Beli')
  RETURNING id
)
INSERT INTO public.blog_translations (post_id, language, title, content, excerpt, meta_title, meta_description)
SELECT id, lang, title, content, excerpt, mt, md FROM p10,
(VALUES
  ('en', 'Rent vs Buy Electric Wheelchair in Malaysia — Which Is Worth It?',
   '<h2>The Rent vs Buy Dilemma</h2><p>Should you rent or buy an electric wheelchair? This is one of the most common questions we get from Malaysian families. The answer depends on your situation.</p><img src="https://placehold.co/800x400/1B2D5B/FFFFFF?text=Rent+vs+Buy" alt="Rent vs buy electric wheelchair Malaysia" /><h2>When to Rent</h2><ul><li><strong>Short-term need (1-6 months):</strong> Post-surgery recovery, temporary injury</li><li><strong>Trying before buying:</strong> Not sure which model suits you</li><li><strong>Budget constraints:</strong> RM400/month vs RM2,400 upfront</li><li><strong>Visiting family:</strong> Need wheelchair for elderly parents'' visit</li></ul><h2>When to Buy</h2><ul><li><strong>Long-term need (1+ years):</strong> Permanent mobility condition</li><li><strong>Daily use:</strong> Used multiple times every day</li><li><strong>Cost over time:</strong> Buying saves money after 6 months of renting</li><li><strong>Customization:</strong> Want specific features and accessories</li></ul><h2>Cost Comparison</h2><p>Let''s compare renting vs buying a Lightweight Model (RM2,400):</p><ul><li><strong>3 months rental:</strong> RM1,200 (saves RM1,200 vs buying)</li><li><strong>6 months rental:</strong> RM2,400 (break-even point)</li><li><strong>12 months rental:</strong> RM4,800 (buying would save RM2,400)</li></ul><blockquote>Our rental-to-own program: Rent first, and we''ll deduct up to 2 months of rental from the purchase price if you decide to buy.</blockquote><img src="https://placehold.co/800x400/2A4080/FFFFFF?text=Cost+Comparison" alt="Rental vs purchase cost comparison" /><h2>FAQ</h2><h3>Can I switch from rental to purchase?</h3><p>Yes! We''ll credit up to 2 months of rental payments towards the purchase price. Many customers start with rental and convert after 2-3 months.</p><h2>Let Us Help You Decide</h2><p>WhatsApp us at 6010-888 9849 and we''ll recommend the best option based on your needs and budget.</p>',
   'Detailed comparison of renting vs buying an electric wheelchair in Malaysia. Cost analysis, break-even point, and rental-to-own program.',
   'Rent vs Buy Electric Wheelchair Malaysia',
   'Should you rent or buy an electric wheelchair in Malaysia? Cost comparison, break-even at 6 months. Rental from RM400/month.'),
  ('ms', 'Sewa vs Beli Kerusi Roda Elektrik — Mana Lebih Berbaloi?',
   '<h2>Dilema Sewa vs Beli</h2><p>Patut sewa atau beli kerusi roda elektrik? Ini soalan paling lazim yang kami terima daripada keluarga Malaysia.</p><img src="https://placehold.co/800x400/1B2D5B/FFFFFF?text=Sewa+vs+Beli" alt="Sewa vs beli kerusi roda elektrik" /><h2>Bila Patut Sewa</h2><ul><li><strong>Keperluan jangka pendek (1-6 bulan):</strong> Pemulihan selepas pembedahan</li><li><strong>Cuba sebelum beli:</strong> Tidak pasti model mana sesuai</li><li><strong>Bajet terhad:</strong> RM400/bulan vs RM2,400 sekaligus</li></ul><h2>Bila Patut Beli</h2><ul><li><strong>Keperluan jangka panjang (1+ tahun)</strong></li><li><strong>Kegunaan harian</strong></li><li><strong>Kos dari masa ke masa:</strong> Membeli jimat selepas 6 bulan menyewa</li></ul><h2>Perbandingan Kos</h2><p>Model Ringan (RM2,400):</p><ul><li><strong>3 bulan sewa:</strong> RM1,200 (jimat RM1,200 vs beli)</li><li><strong>6 bulan sewa:</strong> RM2,400 (titik pulang modal)</li><li><strong>12 bulan sewa:</strong> RM4,800 (beli jimat RM2,400)</li></ul><blockquote>Program sewa-ke-milik: Sewa dulu, kami tolak sehingga 2 bulan sewaan dari harga pembelian.</blockquote><h2>Biar Kami Bantu Anda Memilih</h2><p>WhatsApp kami di 6010-888 9849.</p>',
   'Perbandingan terperinci sewa vs beli kerusi roda elektrik di Malaysia. Analisis kos dan program sewa-ke-milik.',
   'Sewa vs Beli Kerusi Roda Elektrik Malaysia',
   'Patut sewa atau beli kerusi roda elektrik? Perbandingan kos, pulang modal pada 6 bulan. Sewa dari RM400/bulan.'),
  ('zh', '马来西亚电动轮椅租赁vs购买——哪个更值得？',
   '<h2>租赁vs购买的困境</h2><p>应该租赁还是购买电动轮椅？答案取决于您的情况。</p><img src="https://placehold.co/800x400/1B2D5B/FFFFFF?text=租赁vs购买" alt="租赁vs购买电动轮椅" /><h2>何时租赁</h2><ul><li><strong>短期需求（1-6个月）：</strong>术后恢复</li><li><strong>试用后再买</strong></li><li><strong>预算有限：</strong>RM400/月 vs RM2,400一次性</li></ul><h2>何时购买</h2><ul><li><strong>长期需求（1年以上）</strong></li><li><strong>每日使用</strong></li></ul><h2>费用比较</h2><ul><li>3个月租赁：RM1,200</li><li>6个月租赁：RM2,400（盈亏平衡点）</li><li>12个月租赁：RM4,800</li></ul><blockquote>租转购计划：先租赁，最多可抵扣2个月租金。</blockquote><h2>让我们帮您决定</h2><p>WhatsApp我们：6010-888 9849。</p>',
   '马来西亚电动轮椅租赁vs购买详细比较。费用分析和租转购计划。',
   '租赁vs购买电动轮椅马来西亚',
   '应该租赁还是购买电动轮椅？费用比较，6个月盈亏平衡。租赁从RM400/月起。')
) AS t(lang, title, content, excerpt, mt, md);
